import React, { Component } from 'react'

// Bootstrap
import 'bootstrap/dist/js/bootstrap.bundle.js'
import 'bootstrap/dist/css/bootstrap.min.css'


// Custom css
import './assets/css/app.css'
import 'react-toastify/dist/ReactToastify.css';

import { Router, Switch, Route } from 'react-router-dom'
import Dashboard from './Components/Layouts/Dashboard'
import ScrollToTop from './Utils/ScrollToTop'
import history from './Utils/history'
import { getSession } from "./Helpers/Functions";
import { ProtectedRoute } from './Services/ProtectedRoute'
import store from "./app/store";
import { addUser, addCountries } from "./app/Actions";
import ApiRequest from './Services/ApiRequest'
import Axios from './Config/Axios';
import { destroySession } from './Helpers/Functions'
import { countries } from './Helpers/Functions';
import Redirect from "./Utils/history";





import {
	Login,
	Register,
	GetStarted,
	GetStartedLanding,
	BrowseCareer,
	MySpace,
	home,
	FindMentor,
	StartupsMentor,
	HireCoaches,
	BuisnessTeams,
	ViewProfile,
	ProfileSetup,
	ScheduleFeeddback,
	SharePerspective,
	Approved,
	Mentor,
	MentorApplication,
	HireMentor,
	ContactUs,
	PreLaunch,
	MenteeProfile,
	MentorProfile,
	TextEditor,
	UserBoard,
	ForgetPassword,
	VerifyToken,
	ResetPassword,
	DashboardMain,
	JobPosting,
	EmailVerify,
	Applicants,
	PostJob,
	signupMentor,
	AccessDenied,
	MenteeDashboard,
	SpaceSelection,
	EmailVerifySuccess,
	EmailAlreadyVerify,
	Billings,
	Profile,
	Settings,
	PageNotFound,
	Message,
	EditPost,
	ViewPostJob,
	MenteeJobsLists
	// MenteeDashboard,

} from './Pages/pageListAsync'


class App extends Component {
	state={
		countries:{}
	}
	componentDidMount() {
		// console.log('userAuth ' + userAuth)
		Axios.get(`/userAuth`).then(response => {
			if(response.status === 200){
				if(!response.data.user.status){
					Redirect.push('/AccessDenied')
				}
			}
			console.log('Authenticate User',response);
		}).catch(error => {
			destroySession();

		}).finally(() => {
			this.setState({ loading: false });
		});

		// Get Countries
		// console.log('countries ' + countries());

	}
	reduxUpdate() {
		const userDetails = getSession();
		store.dispatch(addUser(userDetails.__userDetail))
		// store.dispatch(addCountries(this.state.countries))
	}

	render() {
		this.reduxUpdate();
		return (
			<React.Fragment>
				<Dashboard>
					<Router history={history}>
						<ScrollToTop>
							<Switch>
								<ProtectedRoute exact path='/' component={home} />
								<Route exact path='/AccessDenied' component={AccessDenied} />
								<Route exact path='/Message' component={Message} />
								<Route exact path='/login' component={Login} />
								<Route exact path='/signupMentor' component={signupMentor} />
								<Route exact path='/signup' component={Register} />
								<Route exact path='/PageNotFound' component={PageNotFound} />
								<ProtectedRoute exact path='/email/verify/EmailVerifySuccess' component={EmailVerifySuccess} />
								<ProtectedRoute exact path='/email/verify/EmailAlreadyVerify' component={EmailAlreadyVerify} />
								<ProtectedRoute exact path='/GetStarted' component={GetStarted} />
								<ProtectedRoute exact path='/GetStartedLanding' component={GetStartedLanding} />
								<ProtectedRoute exact path='/browseCareer' component={BrowseCareer} />
								<ProtectedRoute exact path='/MySpace' component={MySpace} />
								<ProtectedRoute exact path='/home' component={home} />
								<ProtectedRoute exact path='/FindMentor' component={FindMentor} />
								<ProtectedRoute exact path='/StartupsMentor' component={StartupsMentor} />
								<ProtectedRoute exact path='/HireCoaches' component={HireCoaches} />
								<ProtectedRoute exact path='/BuisnessTeams' component={BuisnessTeams} />
								<ProtectedRoute exact path='/ViewProfile' component={ViewProfile} />
								<ProtectedRoute exact path='/ProfileSetup' component={ProfileSetup} />
								<ProtectedRoute exact path='/ScheduleFeeddback' component={ScheduleFeeddback} />
								<ProtectedRoute exact path='/SharePerspective' component={SharePerspective} />
								<ProtectedRoute exact path='/Approved' component={Approved} />
								<ProtectedRoute exact path='/Mentor' component={Mentor} />
								<ProtectedRoute exact path='/MentorApplication' component={MentorApplication} />
								<ProtectedRoute exact path='/HireMentor' component={HireMentor} />
								<ProtectedRoute exact path='/ContactUs' component={ContactUs} />
								<ProtectedRoute exact path='/PreLaunch' component={PreLaunch} />
								<ProtectedRoute exact path='/MentorProfile' component={MentorProfile} />
								<ProtectedRoute exact path='/MenteeProfile' component={MenteeProfile} />
								<ProtectedRoute exact path='/Jobs' component={MenteeJobsLists} />
								<Route exact path='/TextEditor' component={TextEditor} />
								<Route exact path='/ForgetPassword' component={ForgetPassword} />
								<Route exact path='/VerifyToken' component={VerifyToken} />
								<Route exact path='/ResetPassword' component={ResetPassword} />
								<ProtectedRoute exact path='/Dashboard' component={DashboardMain} />
								<ProtectedRoute exact path='/MenteeDashboard' component={MenteeDashboard} />
								<ProtectedRoute exact path='/SpaceSelection' component={SpaceSelection} />
								<ProtectedRoute exact path='/JobPosting' component={JobPosting} />
								<Route exact path="/EmailVerify" component={EmailVerify} />
								<Route exact path='/Applicants' component={Applicants} />
								<ProtectedRoute exact path='/PostJob' component={PostJob} />
								<Route exact path='/Billings' component={Billings} />
								<Route exact path='/Profile' component={Profile} />
								<ProtectedRoute exact path='/EditPost/:postId' component={EditPost} />
								<ProtectedRoute exact path='/ViewPost/:postId' component={ViewPostJob} />
								<ProtectedRoute exact path='/Settings' component={Settings} />
								<ProtectedRoute exact path='/MenteeDashboard' component={MenteeDashboard} />
							</Switch>
						</ScrollToTop>
					</Router>
				</Dashboard>
			</React.Fragment>
		)
		// }
	}
}

export default App
